config.css:
.cms-breadcrumb {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 4px;
    font-size: 0.7rem;
    color: var(--vbwd-text-muted, #6b7280);
    padding: 8px 0 0.25rem;
}
.cms-breadcrumb a, .cms-breadcrumb__link { color: var(--vbwd-color-primary, #3498db); text-decoration: none; }
.cms-breadcrumb a:hover, .cms-breadcrumb__link:hover { text-decoration: underline; }
.cms-breadcrumb__separator { color: var(--vbwd-text-muted, #9ca3af); user-select: none; }
.cms-breadcrumb__current { color: var(--vbwd-text-body, #374151); font-weight: 500; }
